module RefModule (
	input [3:0] a,
	input [3:0] b,
	input cin,
	output [3:0] sum,
	output cout
);wire [3:0] g, p, c;

  assign sum = p ^ c;
  assign cout = g[3] | (p[3] & c[3]);
  assign c[3] = g[2] | (p[2] & c[2]);
  assign c[2] = g[1] | (p[1] & c[1]);
  assign c[1] = g[0] | (p[0] & c[0]);
  assign c[0] = cin;
  assign p = a ^ b;
  assign g = a & b;

endmodule
